file.content:
void editorUpdateRow(erow *row)
__CPROVER_requires(__CPROVER_is_fresh(row, sizeof(erow)))
__CPROVER_requires(0 <= row->size)
__CPROVER_requires(__CPROVER_is_fresh(row->chars, row->size + 1))
__CPROVER_requires(__CPROVER_is_fresh(row->render, 1))
__CPROVER_requires(row->hl == NULL)
__CPROVER_assigns(row->render, row->rsize, row->hl)
__CPROVER_frees(row->render)
__CPROVER_ensures(row->size == __CPROVER_old(row->size))
__CPROVER_ensures(0 <= row->rsize)
{
    unsigned int tabs = 0, nonprint = 0;
    int j, idx;

   /* Create a version of the row we can directly print on the screen,
     * respecting tabs, substituting non printable characters with '?'. */
    free(row->render);
    for (j = 0; j < row->size; j++)
        if (row->chars[j] == TAB) tabs++;

    unsigned long long allocsize =
        (unsigned long long) row->size + tabs*8 + nonprint*9 + 1;
    if (allocsize > UINT32_MAX) {
        printf("Some line of the edited file is too long for kilo\n");
        exit(1);
    }

    row->render = malloc(row->size + tabs*8 + nonprint*9 + 1);
    idx = 0;
    for (j = 0; j < row->size; j++) {
        if (row->chars[j] == TAB) {
            row->render[idx++] = ' ';
            while((idx+1) % 8 != 0) row->render[idx++] = ' ';
        } else {
            row->render[idx++] = row->chars[j];
        }
    }
    row->rsize = idx;
    row->render[idx] = '\0';

